 64→function parseLocation(input: unknown): SubmissionLocation | null {
 65→  if (!input || typeof input !== "object") return null;
 66→  const location = input as { latitude?: unknown; longitude?: unknown };
 67→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 68→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 69→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 70→  return { latitude, longitude };
 71→}
 72→
 73→function hasValue(input: unknown): boolean {
 74→  if (typeof input === "string") return Boolean(input.trim());
 75→  if (typeof input === "boolean") return true;
 76→  if (typeof input === "number") return Number.isFinite(input);
 77→  if (Array.isArray(input)) return input.length > 0;
 78→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 79→  return false;
 80→}
 81→
 82→function trimString(input: unknown, maxLen = 256): string | null {
 83→  if (typeof input !== "string") return null;
 84→  const value = input.trim();
 85→  if (!value) return null;
 86→  return value.slice(0, maxLen);
 87→}
 88→
 89→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 90→  if (!input || typeof input !== "object") return null;
 91→  const raw = input as Record<string, unknown>;
 92→  const deviceId = trimString(raw.deviceId, 128);
 93→  if (!deviceId) return null;
 94→  const platform = trimString(raw.platform, 64);
 95→  const userAgent = trimString(raw.userAgent, 256);
 96→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 97→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
 98→  const isLowEnd = raw.isLowEnd === true;
 99→
100→  return {
101→    deviceId,
102→    platform: platform ?? undefined,
103→    userAgent: userAgent ?? undefined,
104→    deviceMemoryGb: memory,
105→    hardwareConcurrency: cpu,
106→    isLowEnd,
107→  };
108→}
