219→interface IpApiResponse {
220→  latitude?: unknown;
221→  longitude?: unknown;
222→}
223→
224→async function fetchIpLocation(ip: string): Promise<SubmissionLocation | null> {
225→  const target = `https://ipapi.co/${ip}/json/`;
226→  const controller = new AbortController();
227→  const timeout = setTimeout(() => controller.abort(), 3000);
228→  try {
229→    const res = await fetch(target, { signal: controller.signal });
230→    if (!res.ok) return null;
231→    const data = (await res.json()) as IpApiResponse;
232→    const latitude = Number(data?.latitude);
233→    const longitude = Number(data?.longitude);
234→    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
235→    return { latitude, longitude };
236→  } catch {
237→    return null;
238→  } finally {
239→    clearTimeout(timeout);
240→  }
241→}
242→
243→async function getIpLocation(request: Request): Promise<SubmissionLocation | null> {
244→  const forwarded = request.headers.get("x-forwarded-for");
245→  const realIp = request.headers.get("x-real-ip");
246→  const vercelIp = request.headers.get("x-vercel-forwarded-for");
247→  const ip = normalizeIp(vercelIp ?? forwarded ?? realIp);
248→  if (!ip || isPrivateIp(ip)) return null;
249→  return await fetchIpLocation(ip);
250→}
