281→function shouldRunFallbackFraudCheck(event: PointEvent, fraudCheck: SubmissionFraudCheck | null): boolean {
282→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
283→  const secondaryUrl = getSecondaryPhotoUrl(event);
284→  if (!fraudCheck) return Boolean(primaryUrl || secondaryUrl);
285→  if (primaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto)) return true;
286→  if (secondaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto)) return true;
287→  return false;
288→}
289→
290→function mergePhotoFraudMetadata(
291→  existing: SubmissionFraudCheck["primaryPhoto"],
292→  recovered: SubmissionFraudCheck["primaryPhoto"],
293→  hasPhotoUrl: boolean,
294→): SubmissionFraudCheck["primaryPhoto"] {
295→  if (!hasPhotoUrl) return existing ?? null;
296→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
297→  if (recovered) return recovered;
298→  return existing ?? null;
299→}
