346→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
347→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
348→  const userIds = Array.from(
349→    new Set(
350→      sortedEvents
351→        .map((event) => normalizeActorId(event.userId))
352→        .filter((value) => value.length > 0),
353→    ),
354→  );
355→
356→  const profileEntries = await Promise.all(
357→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
358→  );
359→  const profileByUserId = new Map(profileEntries);
360→  const output: AdminSubmissionEvent[] = [];
361→  let fallbackLookups = 0;
362→
363→  for (const event of sortedEvents) {
364→    const normalizedUserId = normalizeActorId(event.userId);
365→    const profile = profileByUserId.get(normalizedUserId) ?? null;
366→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
367→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
368→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
369→    let fraudCheck = getEventFraudCheck(event);
370→    if (shouldRunFallbackFraudCheck(event, fraudCheck) && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
371→      fallbackLookups += 1;
372→      try {
373→        fraudCheck = await buildFallbackFraudCheck(event, fraudCheck);
374→      } catch {
375→        fraudCheck = fraudCheck ?? null;
376→      }
377→    }
378→
379→    output.push({
380→      event,
381→      user: {
382→        id: normalizedUserId || event.userId,
383→        name,
384→        email,
385→      },
386→      fraudCheck,
387→    });
388→  }
389→
390→  return output;
391→}
