393→async function buildCombinedEvents(): Promise<PointEvent[]> {
394→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
395→  const legacySubmissions = await getLegacySubmissions();
396→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
397→  const seenExternalIds = new Set(
398→    merged
399→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
400→      .filter((value) => value.length > 0),
401→  );
402→  const seenPointIds = new Set(merged.map((event) => event.pointId));
403→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
404→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
405→    if (externalId && seenExternalIds.has(externalId)) continue;
406→    if (seenPointIds.has(seedEvent.pointId)) continue;
407→    merged.push(seedEvent);
408→    if (externalId) seenExternalIds.add(externalId);
409→    seenPointIds.add(seedEvent.pointId);
410→  }
411→  return merged;
412→}
