414→export async function GET(request: Request): Promise<Response> {
415→  const auth = await requireUser(request);
416→  const authContext = toSubmissionAuthContext(auth);
417→  const url = new URL(request.url);
418→  const view = url.searchParams.get("view");
419→  const lat = url.searchParams.get("lat");
420→  const lng = url.searchParams.get("lng");
421→  const radius = url.searchParams.get("radius");
422→  const requestedScope = normalizeMapScope(url.searchParams.get("scope"));
423→  const canUseExpandedScope = requestedScope !== "bonamoussadi";
424→  if (canUseExpandedScope && !authContext) return errorResponse("Unauthorized", 401);
425→  if (canUseExpandedScope && !authContext.isAdmin) return errorResponse("Forbidden", 403);
426→  const effectiveScope = canUseExpandedScope ? requestedScope : "bonamoussadi";
427→  const canUsePublicCache = !authContext && !canUseExpandedScope;
428→
429→  try {
430→    const allEvents = await buildCombinedEvents();
431→    const scopedEvents = allEvents.filter((event) => {
432→      if (effectiveScope === "global") return true;
433→      if (effectiveScope === "cameroon") return isWithinCameroon(event.location);
434→      return isWithinBonamoussadi(event.location);
435→    });
436→
437→    if (view === "events") {
438→      if (!authContext) {
439→        return jsonResponse(redactEventUserIds(scopedEvents), {
440→          status: 200,
441→          headers: {
442→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
443→          },
444→        });
445→      }
446→      const responseEvents = filterEventsForViewer(scopedEvents, authContext);
447→      return jsonResponse(responseEvents, { status: 200 });
448→    }
449→
450→    if (view === "admin_events") {
451→      const adminAccess = resolveAdminViewAccess(authContext);
452→      if (adminAccess === "unauthorized") return errorResponse("Unauthorized", 401);
453→      if (adminAccess === "forbidden") return errorResponse("Forbidden", 403);
454→      const adminEvents = await buildAdminSubmissionEvents(scopedEvents);
455→      return jsonResponse(adminEvents, { status: 200 });
456→    }
457→
458→    let projected = projectPointsFromEvents(scopedEvents);
459→
460→    if (lat && lng && radius) {
461→      const latitude = Number(lat);
462→      const longitude = Number(lng);
463→      const radiusKm = Number(radius);
464→      if (Number.isFinite(latitude) && Number.isFinite(longitude) && Number.isFinite(radiusKm)) {
465→        projected = projected.filter((point) => haversineKm(point.location, { latitude, longitude }) <= radiusKm);
466→      }
467→    }
468→
469→    return jsonResponse(projected, {
470→      status: 200,
471→      headers: canUsePublicCache
472→        ? {
473→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
474→          }
475→        : undefined,
476→    });
477→  } catch (error) {
478→    if (isStorageUnavailableError(error)) {
479→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
480→    }
481→    throw error;
482→  }
483→}
