485→export async function POST(request: Request): Promise<Response> {
486→  const auth = await requireUser(request);
487→  if (!auth) return errorResponse("Unauthorized", 401);
488→  const authContext = toSubmissionAuthContext(auth);
489→  const isAdminUser = authContext?.isAdmin === true;
490→
491→  let body: SubmissionInput;
492→  try {
493→    body = (await request.json()) as SubmissionInput;
494→  } catch {
495→    return errorResponse("Invalid JSON body", 400);
496→  }
497→
498→  const category = normalizeCategory(body?.category as string | undefined);
499→  if (!category || !allowedCategories.includes(category)) {
500→    return errorResponse("Invalid category", 400);
501→  }
502→
503→  const eventType = normalizeEventType(body?.eventType);
504→  const location = parseLocation(body?.location);
505→  const details = normalizeEnrichPayload(
506→    category,
507→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
508→  );
509→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
510→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
511→  if (clientDevice) {
512→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
513→    details.clientDevice = clientDevice;
514→  } else if ("clientDevice" in details) {
515→    delete details.clientDevice;
516→  }
517→
518→  const imageBase64 = body?.imageBase64 as string | undefined;
519→  if (!imageBase64) return errorResponse("Photo is required", 400);
520→  const parsedPhoto = parseImagePayload(imageBase64);
521→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
522→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
523→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
524→  }
525→
526→  const ipLocation = await getIpLocation(request);
527→  let photoLocation: SubmissionLocation | null = null;
528→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
529→
530→  try {
531→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer, {
532→      source: "upload_buffer",
533→      mime: parsedPhoto.mime,
534→      ext: parsedPhoto.ext,
535→      byteLength: parsedPhoto.imageBuffer.byteLength,
536→    });
537→    if (primaryPhotoMetadata.gps) {
538→      photoLocation = primaryPhotoMetadata.gps;
539→      if (location) {
540→        const distance = haversineKm(location, photoLocation);
541→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
542→      }
543→      if (ipLocation) {
544→        const distance = haversineKm(ipLocation, photoLocation);
545→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
546→      }
547→    } else if (!location && !ipLocation) {
548→      return errorResponse("Photo is missing GPS metadata", 400);
549→    }
550→  } catch {
551→    primaryPhotoMetadata = {
552→      gps: null,
553→      capturedAt: null,
554→      deviceMake: null,
555→      deviceModel: null,
556→      exifStatus: "parse_error",
557→      exifReason: `Unexpected EXIF extraction failure (mime=${parsedPhoto.mime}; ext=${parsedPhoto.ext}; bytes=${parsedPhoto.imageBuffer.byteLength})`,
558→      exifSource: "upload_buffer",
559→    };
560→    if (!location && !ipLocation) {
561→      return errorResponse("Unable to read photo GPS metadata", 400);
562→    }
563→  }
564→
565→  const finalLocation = photoLocation ?? location ?? ipLocation;
566→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
567→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
568→    return errorResponse(
569→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
570→      400,
571→    );
572→  }
573→
574→  try {
575→    const existingEvents = await buildCombinedEvents();
576→    const projectedExisting = projectPointsFromEvents(existingEvents);
577→    let pointId = typeof body.pointId === "string" && body.pointId.trim() ? body.pointId.trim() : crypto.randomUUID();
578→
579→    if (eventType === "CREATE_EVENT") {
580→      const createError = validateCreatePayload(category, details);
581→      if (createError) return errorResponse(createError, 400);
582→    } else {
583→      if (!body.pointId || typeof body.pointId !== "string" || !body.pointId.trim()) {
584→        return errorResponse("pointId is required for ENRICH_EVENT", 400);
585→      }
586→      pointId = body.pointId.trim();
587→      const target = projectedExisting.find((point) => point.pointId === pointId);
588→      if (!target) return errorResponse("Target point not found", 404);
589→      if (target.category !== category) return errorResponse("Category mismatch for target point", 400);
590→
591→      const submittedEntries = Object.entries(details).filter(([, value]) => hasValue(value));
592→      const allowedGaps = new Set(target.gaps);
593→      const filteredEntries = submittedEntries.filter(([field]) => {
594→        const canonical =
595→          field === "hours"
596→            ? "openingHours"
597→            : field === "merchantId"
598→              ? "merchantIdByProvider"
599→              : field === "hasCashAvailable"
600→                ? "hasMin50000XafAvailable"
601→                : field;
602→        return isEnrichFieldAllowed(category, canonical) && allowedGaps.has(canonical);
603→      });
604→      if (!filteredEntries.length) {
605→        return errorResponse("ENRICH_EVENT must include at least one currently missing field", 400);
606→      }
607→      const filteredDetails: SubmissionDetails = {};
608→      for (const [key, value] of filteredEntries) {
609→        filteredDetails[key] = value;
610→      }
611→      Object.assign(details, filteredDetails);
612→      for (const key of Object.keys(details)) {
613→        if (!Object.prototype.hasOwnProperty.call(filteredDetails, key)) {
614→          delete details[key];
615→        }
616→      }
617→      if (clientDevice) {
618→        details.clientDevice = clientDevice;
619→      }
620→    }
621→
622→    const eventId = crypto.randomUUID();
623→    let photoUrl: string | undefined;
624→    try {
625→      photoUrl = await uploadSubmissionPhoto(eventId, parsedPhoto.imageBuffer, parsedPhoto.mime, parsedPhoto.ext);
626→    } catch (error) {
627→      const raw = error instanceof Error ? error.message : String(error);
628→      const lower = raw.toLowerCase();
629→      if (lower.includes("blob") && lower.includes("token")) return errorResponse("Blob storage is not configured", 500);
630→      return errorResponse("Unable to store photo", 500);
631→    }
632→    details.hasPhoto = true;
633→
634→    let secondaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
635→    const secondImageBase64 = body?.secondImageBase64 as string | undefined;
636→    if (secondImageBase64) {
637→      const parsedSecondPhoto = parseImagePayload(secondImageBase64);
638→      if (!parsedSecondPhoto) return errorResponse("Invalid photo format", 400);
639→      if (parsedSecondPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
640→        return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
641→      }
642→
643→      try {
644→        secondaryPhotoMetadata = await extractPhotoMetadata(parsedSecondPhoto.imageBuffer, {
645→          source: "upload_buffer",
646→          mime: parsedSecondPhoto.mime,
647→          ext: parsedSecondPhoto.ext,
648→          byteLength: parsedSecondPhoto.imageBuffer.byteLength,
649→        });
650→      } catch {
651→        secondaryPhotoMetadata = {
652→          gps: null,
653→          capturedAt: null,
654→          deviceMake: null,
655→          deviceModel: null,
656→          exifStatus: "parse_error",
657→          exifReason: `Unexpected EXIF extraction failure (mime=${parsedSecondPhoto.mime}; ext=${parsedSecondPhoto.ext}; bytes=${parsedSecondPhoto.imageBuffer.byteLength})`,
658→          exifSource: "upload_buffer",
659→        };
660→      }
661→
662→      try {
663→        const secondPhotoUrl = await uploadSubmissionPhoto(
664→          `${eventId}-second`,
665→          parsedSecondPhoto.imageBuffer,
666→          parsedSecondPhoto.mime,
667→          parsedSecondPhoto.ext,
668→        );
669→        details.secondPhotoUrl = secondPhotoUrl;
670→        details.hasSecondaryPhoto = true;
671→      } catch {
672→        return errorResponse("Unable to store photo", 500);
673→      }
674→    }
675→
676→    const primaryPhotoFraud = buildPhotoFraudMetadata({
677→      extracted: primaryPhotoMetadata,
678→      submissionLocation: location,
679→      ipLocation,
680→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
681→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
682→    });
683→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
684→      extracted: secondaryPhotoMetadata,
685→      submissionLocation: location,
686→      ipLocation,
687→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
688→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
689→    });
690→    details.fraudCheck = buildSubmissionFraudCheck({
691→      submissionLocation: location,
692→      effectiveLocation: finalLocation,
693→      ipLocation,
694→      primaryPhoto: primaryPhotoFraud,
695→      secondaryPhoto: secondaryPhotoFraud,
696→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
697→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
698→    });
699→
700→    const now = new Date().toISOString();
701→    const newEvent: PointEvent = {
702→      id: eventId,
703→      pointId,
704→      eventType,
705→      userId: auth.id,
706→      category,
707→      location: finalLocation,
708→      details,
709→      photoUrl,
710→      createdAt: now,
711→      source: typeof details.source === "string" ? details.source : undefined,
712→      externalId: typeof details.externalId === "string" ? details.externalId : undefined,
713→    };
714→
715→    await insertPointEvent(newEvent);
716→
717→    const exifDeviceMake = primaryPhotoMetadata?.deviceMake ?? null;
718→    const exifDeviceModel = primaryPhotoMetadata?.deviceModel ?? null;
719→    const logPayload = {
720→      eventId,
721→      userId: auth.id,
722→      category,
723→      deviceId: clientDevice?.deviceId ?? null,
724→      clientPlatform: clientDevice?.platform ?? null,
725→      clientUserAgent: clientDevice?.userAgent ?? requestUserAgent ?? null,
726→      clientMemoryGb: clientDevice?.deviceMemoryGb ?? null,
727→      clientCpuCores: clientDevice?.hardwareConcurrency ?? null,
728→      clientIsLowEnd: clientDevice?.isLowEnd ?? null,
729→      exifDeviceMake,
730→      exifDeviceModel,
731→    };
732→    if (process.env.NODE_ENV !== "production") {
733→      console.info("[SUBMISSION_DEVICE]", JSON.stringify(logPayload));
734→    }
735→
736→    const profile = await getUserProfile(auth.id);
737→    if (profile) {
738→      profile.XP = (profile.XP ?? 0) + BASE_EVENT_XP;
739→      await upsertUserProfile(auth.id, profile);
740→    }
741→
742→    return jsonResponse(newEvent, { status: 201 });
743→  } catch (error) {
744→    if (isStorageUnavailableError(error)) {
745→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
746→    }
747→    throw error;
748→  }
749→}
