 14→function normalizeMapScope(input: unknown): MapScope {
 15→  if (typeof input !== "string") return "bonamoussadi";
 16→  const normalized = input.trim().toLowerCase() as MapScope;
 17→  if (!VALID_MAP_SCOPES.has(normalized)) return "bonamoussadi";
 18→  return normalized;
