 21→function parseXp(input: unknown): number {
 22→  const value = typeof input === "number" ? input : Number(input);
 23→  if (!Number.isFinite(value)) return 0;
 24→  return Math.max(0, Math.round(value));
 25→}
 26→
 27→function isUuid(input: string): boolean {
 28→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(input);
 29→}
 30→
 31→function deterministicUuid(seed: string): string {
 32→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 33→  hex[12] = "5";
 34→  const variant = parseInt(hex[16], 16);
 35→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 36→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 37→}
 38→
 39→function normalizeEventId(input: string): string {
 40→  const trimmed = input.trim();
 41→  if (isUuid(trimmed)) return trimmed.toLowerCase();
 42→  return deterministicUuid(`event:${trimmed}`);
 43→}
 44→
 45→function normalizeCreatedAt(input: unknown): string {
 46→  if (typeof input === "string") {
 47→    const parsed = new Date(input);
 48→    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
 49→  }
 50→  return new Date().toISOString();
 51→}
